const BOGOTA_OFFSET_HOURS = -5;
const WINDOW_START_HOUR = 8;
const WINDOW_END_HOUR = 23;
const MONTHS = ['ene', 'feb', 'mar', 'abr', 'may', 'jun', 'jul', 'ago', 'sep', 'oct', 'nov', 'dic'];

const compact = (value) => String(value ?? '').trim();
const normalizeText = (value) =>
