function toBogotaParts(date = new Date()) {
  const shifted = new Date(date.getTime() + BOGOTA_OFFSET_HOURS * 60 * 60 * 1000);
  return {
    year: shifted.getUTCFullYear(),
    month: shifted.getUTCMonth() + 1,
    day: shifted.getUTCDate(),
    hour: shifted.getUTCHours(),
    minute: shifted.getUTCMinutes(),
    second: shifted.getUTCSeconds(),
  };
}

function bogotaDateToUtc(year, month, day, hour = 0, minute = 0, second = 0) {
  return new Date(Date.UTC(year, month - 1, day, hour - BOGOTA_OFFSET_HOURS, minute, second));
}

function nextDay(year, month, day) {
  const date = new Date(Date.UTC(year, month - 1, day) + 24 * 60 * 60 * 1000);
  return {
    year: date.getUTCFullYear(),
    month: date.getUTCMonth() + 1,
    day: date.getUTCDate(),
  };
}

function normalizeToAllowedWindow(date) {
  const parts = toBogotaParts(date);
  if (parts.hour < WINDOW_START_HOUR) {
    return bogotaDateToUtc(parts.year, parts.month, parts.day, WINDOW_START_HOUR, 0, 0);
  }
  if (parts.hour >= WINDOW_END_HOUR) {
    const tomorrow = nextDay(parts.year, parts.month, parts.day);
    return bogotaDateToUtc(tomorrow.year, tomorrow.month, tomorrow.day, WINDOW_START_HOUR, 0, 0);
  }
  return date;
}

function parseDateOnly(value) {
  const source = compact(value);
  if (!source) return null;
  const match = source.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (match) {
    return {
      year: Number(match[1]),
      month: Number(match[2]),
      day: Number(match[3]),
    };
  }
  const date = new Date(source);
  if (Number.isNaN(date.getTime())) return null;
  return {
    year: date.getUTCFullYear(),
    month: date.getUTCMonth() + 1,
    day: date.getUTCDate(),
  };
}

function formatDateForTemplate(parts, includeYear) {
  if (!parts) return null;
  const monthLabel = MONTHS[(parts.month || 1) - 1] || MONTHS[0];
  return includeYear
    ? `${parts.day} de ${monthLabel} de ${parts.year}`
    : `${parts.day} de ${monthLabel}`;
}

function parseCsv(text) {
  const rows = [];
  let row = [];
  let cell = '';
  let inQuotes = false;
  for (let index = 0; index < text.length; index += 1) {
    const char = text[index];
    const next = text[index + 1];
    if (inQuotes) {
      if (char === '"' && next === '"') {
        cell += '"';
        index += 1;
      } else if (char === '"') {
        inQuotes = false;
      } else {
        cell += char;
      }
      continue;
    }

    if (char === '"') {
      inQuotes = true;
      continue;
    }
    if (char === ',') {
      row.push(cell);
      cell = '';
      continue;
    }
    if (char === '\n') {
      row.push(cell);
      rows.push(row);
      row = [];
      cell = '';
      continue;
    }
    if (char === '\r') {
      continue;
    }
    cell += char;
  }
  row.push(cell);
  rows.push(row);
  return rows.filter((entry) => entry.some((value) => compact(value) !== ''));
}

function normalizeHeader(value) {
  return normalizeText(value).replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '');
}

function pick(row, keys) {
  for (const key of keys) {
    if (row[key] !== undefined && row[key] !== null && compact(row[key]) !== '') return compact(row[key]);
  }
  return null;
}

function normalizePhone(rawValue) {
  const digits = String(rawValue || '').replace(/\D+/g, '').trim();
  if (!digits) return null;
  if (digits.startsWith('0057') && digits.length >= 12) return digits.slice(2);
  if (digits.startsWith('57') && digits.length >= 12 && digits.length <= 15) return digits;
  if (digits.length === 10) return '57' + digits;
  return null;
}

function mergeSnapshot(base = {}, row = {}) {
