const input = $json || {};
const BOGOTA_OFFSET_HOURS = -5;
const WINDOW_START_HOUR = 8;
const WINDOW_END_HOUR = 23;

function toBogotaParts(date = new Date()) {
  const shifted = new Date(date.getTime() + BOGOTA_OFFSET_HOURS * 60 * 60 * 1000);
  return {
    year: shifted.getUTCFullYear(),
    month: shifted.getUTCMonth() + 1,
    day: shifted.getUTCDate(),
    hour: shifted.getUTCHours(),
    minute: shifted.getUTCMinutes(),
  };
}

function bogotaDateToUtc(year, month, day, hour = 0, minute = 0) {
  return new Date(Date.UTC(year, month - 1, day, hour - BOGOTA_OFFSET_HOURS, minute, 0));
}

function nextDay(year, month, day) {
  const date = new Date(Date.UTC(year, month - 1, day) + 24 * 60 * 60 * 1000);
  return {
    year: date.getUTCFullYear(),
    month: date.getUTCMonth() + 1,
    day: date.getUTCDate(),
  };
}

function normalizeToAllowedWindow(date) {
  const parts = toBogotaParts(date);
  if (parts.hour < WINDOW_START_HOUR) {
    return bogotaDateToUtc(parts.year, parts.month, parts.day, WINDOW_START_HOUR, 0);
  }
  if (parts.hour >= WINDOW_END_HOUR) {
    const tomorrow = nextDay(parts.year, parts.month, parts.day);
    return bogotaDateToUtc(tomorrow.year, tomorrow.month, tomorrow.day, WINDOW_START_HOUR, 0);
  }
  return date;
}

function stripCodeFences(str) {
  return String(str || '')
    .trim()
    .replace(/^\s*```json\s*/i, '')
    .replace(/^\s*```\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
}

function extractFirstJsonObject(text) {
  const source = String(text || '');
  const start = source.indexOf('{');
  if (start === -1) return null;
  let depth = 0;
  let inString = false;
  let escape = false;
  for (let index = start; index < source.length; index += 1) {
    const char = source[index];
    if (inString) {
      if (escape) escape = false;
      else if (char === '\\') escape = true;
      else if (char === '"') inString = false;
      continue;
    }
    if (char === '"') {
      inString = true;
      continue;
    }
    if (char === '{') depth += 1;
    else if (char === '}') {
      depth -= 1;
      if (depth === 0) return source.slice(start, index + 1);
    }
  }
  return null;
}

function parseJsonSafe(value) {
  const cleaned = stripCodeFences(value);
  try {
    return JSON.parse(cleaned);
  } catch {
    const candidate = extractFirstJsonObject(cleaned);
    if (!candidate) return null;
    try {
      return JSON.parse(candidate);
    } catch {
      return null;
    }
  }
}

function parseDateOnly(value) {
  const source = String(value || '').trim();
  if (!source) return null;
  const match = source.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (match) {
    return new Date(Date.UTC(Number(match[1]), Number(match[2]) - 1, Number(match[3]), 12, 0, 0));
  }
  const parsed = new Date(source);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function fallbackReminderDelayMinutes(fechaInicio) {
  const start = parseDateOnly(fechaInicio);
  if (!start) return 120;
  const diffMs = start.getTime() - Date.now();
  const diffHours = diffMs / (1000 * 60 * 60);
  if (diffHours <= 48) return 30;
  if (diffHours <= 24 * 7) return 120;
  return 720;
}

const rawText =
  input.text ||
  input.output ||
  input.response ||
  input.message ||
  (Array.isArray(input.data) ? input.data[0]?.text : '') ||
  '';
const parsed = parseJsonSafe(rawText);
const fallbackDelay = fallbackReminderDelayMinutes(input.payload?.fecha_inicio);
let delay = Number(parsed?.reminder_delay_minutes);
if (!Number.isFinite(delay) || delay <= 0) delay = fallbackDelay;
delay = Math.max(15, Math.min(Math.round(delay), 10080));

const reminderAt = normalizeToAllowedWindow(new Date(Date.now() + delay * 60 * 1000));

return [
  {
    json: {
      ...input,
      reminder_delay_minutes: delay,
      reminder_reason: String(parsed?.reason || `fallback:${fallbackDelay}`).trim(),
      reminder_planner_raw: String(rawText || '').slice(0, 4000),
      reminder_at: reminderAt.toISOString(),
    },
  },
];

